"""Workflow pack path resolution for rebase-plan (no environment reads)."""

from __future__ import annotations

from pathlib import Path

REBASE_PLAN_WORKFLOW_DIR_ENV = "REBASE_PLAN_WORKFLOW_DIR"

_WORKFLOWS_ROOT = Path(__file__).resolve().parent.parent.parent / "workflows"


def default_pack_root() -> Path:
    return _WORKFLOWS_ROOT / "rebase-plan"


def resolve_pack_root(override_dir: str) -> Path:
    """Resolve pack root from an explicit directory override (may be empty for default)."""
    raw = override_dir.strip()
    return Path(raw).expanduser() if raw else default_pack_root()


def workflow_yaml_path(pack_root: Path) -> Path:
    return pack_root / "workflow.yaml"

"""Render rebase-plan workflow YAML and invoke flow CLI."""

from __future__ import annotations

