@dataclass(frozen=True, slots=True)
class RebasePlanRunResult:
    exit_code: int
    run_dir: Path
    log_path: Path
    plan_branch_url: str | None = None
    issues: list[dict[str, Any]] | None = None
    flow_log_tail: str | None = None


def _github_compare_url(owner: str, repo: str, base_branch: str, head_branch: str) -> str:
    return f"https://github.com/{owner}/{repo}/compare/{base_branch}...{head_branch}"


def _load_issues_manifest(run_dir: Path) -> list[dict[str, Any]]:
    manifest_path = run_dir / "artifacts" / "issues-manifest.json"
    if not manifest_path.is_file():
        return []
    payload = json.loads(manifest_path.read_text(encoding="utf-8"))
    if not isinstance(payload, list):
        return []
    return [entry for entry in payload if isinstance(entry, dict)]


def _resolve_plan_branch_url(run_dir: Path) -> str | None:
    acquire_path = run_dir / "artifacts" / "acquire.json"
    if not acquire_path.is_file():
        return None
    acquire = json.loads(acquire_path.read_text(encoding="utf-8"))
    owner = acquire.get("repo_owner")
    repo_name = acquire.get("repo_name")
    base_branch = acquire.get("base_branch")
    branch = acquire.get("branch")
    if not all(isinstance(v, str) and v for v in (owner, repo_name, base_branch, branch)):
        return None
    return _github_compare_url(owner, repo_name, base_branch, branch)


async def execute_rebase_plan(
    params: RebasePlanInput,
) -> tuple[dict[str, Any], bool, str | None]:
    """Run rebase-plan flow; return (content, success, error detail)."""
    try:
        runner = RebasePlanRunner.from_env()
        result = await runner.run_async(params)
    except Exception as exc:  # noqa: BLE001 — tool boundary surfaces structured failure
        return (
            {
                "rebase_plan": {
                    "ok": False,
                    "error": str(exc),
                }
            },
            False,
            str(exc),
        )

    issues = result.issues or []
    body = {
        "rebase_plan": {
            "ok": result.exit_code == 0,
            "exit_code": result.exit_code,
            "plan_branch_url": result.plan_branch_url,
            "issues": issues,
            "run_dir": str(result.run_dir),
            "log_path": str(result.log_path),
            "flow_log_tail": result.flow_log_tail,
        }
    }
    if result.exit_code != 0:
        detail = f"flow exited with code {result.exit_code}"
        if result.flow_log_tail:
            detail = f"{detail}\n{result.flow_log_tail}"
        return body, False, detail
    return body, True, None


class RebasePlanRunner:
    """Render rebase-plan workflow YAML and run the flow pack."""

    def __init__(
        self,
        settings: RebasePlanSettings,
        *,
        workflow_yaml_path: Path,
        prompts: dict[str, str] | None = None,
    ) -> None:
        self._settings = settings
        self._workflow_yaml_path = workflow_yaml_path
        self._prompts_override = prompts

    @classmethod
    def from_env(cls) -> RebasePlanRunner:
        settings = load_rebase_plan_settings()
        pack_root = resolve_pack_root(os.environ.get(REBASE_PLAN_WORKFLOW_DIR_ENV, ""))
        yaml_path = workflow_yaml_path(pack_root)
        return cls(settings, workflow_yaml_path=yaml_path)

    def render_workflow_yaml(self, yaml_source: str) -> tuple[dict[str, str], str]:
        prompts = self._prompts_override or fetch_rebase_plan_prompts_for_credentials(
            public_key=self._settings.langfuse_public_key,
            secret_key=self._settings.langfuse_secret_key,
            base_url=self._settings.langfuse_base_url,
        )
        required_placeholders_present(yaml_source)
        return prompts, substitute_langfuse_tokens(yaml_source, prompts)

    def _flow_params(self, params: RebasePlanInput) -> dict[str, str]:
        guidance = params.additional_guidance or ""
        return {
            "legacy_repo_url": sanitize_source_repo(params.legacy_repo_url),
            "discovery_ref": params.discovery_ref,
            "discovery_path": params.discovery_path,
            "proposal_ref": params.proposal_ref.strip(),
            "proposal_path": params.proposal_path.strip(),
            "new_repo_url": sanitize_source_repo(params.new_repo_url),
            "new_base_branch": params.new_base_branch,
            "new_project_url": params.new_project_url.strip(),
            "additional_guidance": guidance,
        }

    async def run_async(self, params: RebasePlanInput) -> RebasePlanRunResult:
        yaml_path = self._workflow_yaml_path
        if not yaml_path.is_file():
            raise FileNotFoundError(f"workflow yaml not found: {yaml_path}")

        pack_root = yaml_path.parent
        yaml_source = yaml_path.read_text(encoding="utf-8")
        prompts, _rendered = self.render_workflow_yaml(yaml_source)
        run_dir, rendered_path = prepare_run_directory(
            pack_root=pack_root,
            yaml_source=yaml_source,
            prompts=prompts,
            workflow_name="rebase-plan",
        )

        log_path = run_dir / "flow.log"
        exit_code = await run_flow_async(
            workflow_yaml=rendered_path,
            cwd=run_dir,
            params=self._flow_params(params),
            log_path=log_path,
            env={"GITHUB_TOKEN": self._settings.github_token},
        )
        plan_branch_url: str | None = None
        issues: list[dict[str, Any]] | None = None
        log_tail = flow_log_tail(log_path) if log_path.is_file() else None
        if exit_code == 0:
            plan_branch_url = _resolve_plan_branch_url(run_dir)
            issues = _load_issues_manifest(run_dir)
            if plan_branch_url is None:
                try:
                    summary = resolve_flow_summary(run_dir, log_path=log_path)
                except FileNotFoundError:
                    summary = None
                if summary and "http" in summary:
                    for part in summary.split():
                        if part.startswith("http"):
                            plan_branch_url = part.rstrip()
                            break

        return RebasePlanRunResult(
            exit_code=exit_code,
            run_dir=run_dir,
            log_path=log_path,
            plan_branch_url=plan_branch_url,
            issues=issues,
            flow_log_tail=log_tail,
        )

    def run(self, params: RebasePlanInput) -> int:
        result = asyncio.run(self.run_async(params))
        return result.exit_code


